mapper.select:
SELECT
    id,
    order_id as "orderId",
    warehouse_id as "warehouseId",
    user_id as "userId",
    saga_id as "sagaId",
    priority,
    fulfillment_type as "fulfillmentType",
    shipping_method as "shippingMethod",
    carrier,
    tracking_number as "trackingNumber",
    total_items as "totalItems",
    state_id as "stateId",
    flow_id as "flowId",
    estimated_ship_date as "estimatedShipDate",
    estimated_delivery_date as "estimatedDeliveryDate",
    created_time as "createdTime"
FROM fulfillment_orders

    AND order_id = #{orderId}
    AND warehouse_id = #{warehouseId}
    AND user_id = #{userId}
    AND priority = #{priority}
    AND fulfillment_type = #{fulfillmentType}
    AND carrier = #{carrier}
    AND state_id = #{stateId}
    AND tracking_number = #{trackingNumber}

${orderby} ${pagination}

SELECT count(*) FROM fulfillment_orders

    AND order_id = #{orderId}
    AND warehouse_id = #{warehouseId}
    AND user_id = #{userId}
    AND priority = #{priority}
    AND fulfillment_type = #{fulfillmentType}
    AND carrier = #{carrier}
    AND state_id = #{stateId}
    AND tracking_number = #{trackingNumber}
